@app.route("/api/invoices/<int:invoice_id>/download", methods=["GET"])
def download_invoice(invoice_id):
    """
    Downloads a specific invoice by its ID.

    Assumes:
    - Authentication middleware has already verified the user and their
      authorization to access this specific invoice_id.
    - Invoice files are stored in a designated directory.
    """
    invoice_filename = f"invoice_{invoice_id}.pdf"
    invoice_filepath = os.path.join(INVOICE_STORAGE_DIR, invoice_filename)

    # In a real application, you would also perform a database lookup here
    # to ensure the invoice_id exists and belongs to the authenticated user.
    # For this example, we're just checking file existence.

    if not os.path.exists(invoice_filepath):
        # Log this event for auditing/debugging
        app.logger.warning(f"Attempted to download non-existent invoice: {invoice_id}")
        abort(404, description="Invoice not found.")

    try:
        return send_file(
            invoice_filepath,
            mimetype="application/pdf",
            as_attachment=True,
            download_name=invoice_filename
        )
    except Exception as e:
        app.logger.error(f"Error serving invoice {invoice_id}: {e}")
        abort(500, description="Could not process your download request.")

